import{_ as l,o as a,c as r,ae as e}from"./chunks/framework.DrYEjkpc.js";const k=JSON.parse('{"title":"Skill Creator","description":"","frontmatter":{},"headers":[],"relativePath":"radar/tech-skill-creator.md","filePath":"radar/tech-skill-creator.md"}'),o={name:"radar/tech-skill-creator.md"};function i(d,t,n,s,h,c){return a(),r("div",null,[...t[0]||(t[0]=[e('<h1 id="skill-creator" tabindex="-1">Skill Creator <a class="header-anchor" href="#skill-creator" aria-label="Permalink to &quot;Skill Creator&quot;">​</a></h1><blockquote><p><strong>分类</strong>: Skill 生成 | <strong>成熟度</strong>: 🟢 成熟期 | <strong>综合评分</strong>: 0.71</p></blockquote><hr><h2 id="基本信息" tabindex="-1">基本信息 <a class="header-anchor" href="#基本信息" aria-label="Permalink to &quot;基本信息&quot;">​</a></h2><p><strong>一句话描述</strong>: Anthropic 官方在 Claude 文档中为 Agent Skills 提供的创建指引，把&quot;写 Skill&quot;变成&quot;写测试 prompt → 跑 Eval → 看通过率 → 改 description → 再跑&quot;的工程循环。</p><p><strong>来源</strong>:</p><ul><li>工业实现 - Anthropic 官方</li><li>出现在 Claude 官方文档与 Claude Code 工作流中</li></ul><p><strong>链接</strong>:</p><ul><li>官方文档：<a href="https://docs.claude.com/en/docs/agents-and-tools/agent-skills" target="_blank" rel="noreferrer">Agent Skills - Claude Docs</a></li><li>注：曾流传的 <code>anthropics/courses/skill-creator</code> 路径<strong>已不存在</strong>，相关能力现集成在 Claude Code / Claude API 工作流中</li></ul><hr><h2 id="核心技术" tabindex="-1">核心技术 <a class="header-anchor" href="#核心技术" aria-label="Permalink to &quot;核心技术&quot;">​</a></h2><h3 id="核心原理" tabindex="-1">核心原理 <a class="header-anchor" href="#核心原理" aria-label="Permalink to &quot;核心原理&quot;">​</a></h3><p>把传统&quot;凭感觉写 Skill&quot;变成可量化的工程循环：</p><ol><li><strong>引导式创建</strong> — 通过结构化问答帮助作者拆解需求，而非面对空白 SKILL.md。</li><li><strong>测试 prompt + Eval 闭环</strong> — 让作者写 10+ 个测试 prompt，批量运行可视化通过率。</li><li><strong>description 自动优化器</strong> — 通过措辞调整提升 Skill 触发命中率，类似 SEO 标题优化。</li></ol><h3 id="核心创新" tabindex="-1">核心创新 <a class="header-anchor" href="#核心创新" aria-label="Permalink to &quot;核心创新&quot;">​</a></h3><ul><li>把 Skill 当作&quot;可被测试的软件构件&quot;而非自然语言文档</li><li>引入 description-as-trigger 的概念，让生成阶段就关注路由可见性</li></ul><hr><h2 id="技术细节" tabindex="-1">技术细节 <a class="header-anchor" href="#技术细节" aria-label="Permalink to &quot;技术细节&quot;">​</a></h2><h3 id="主要能力" tabindex="-1">主要能力 <a class="header-anchor" href="#主要能力" aria-label="Permalink to &quot;主要能力&quot;">​</a></h3><ul><li>引导式 Skill 起草</li><li>批量 Eval 与通过率可视化</li><li>description 自动 A/B 优化</li></ul><h3 id="适用场景" tabindex="-1">适用场景 <a class="header-anchor" href="#适用场景" aria-label="Permalink to &quot;适用场景&quot;">​</a></h3><ul><li>Claude Code 用户从零创建 Skill</li><li>已有 Skill 的质量回归测试</li></ul><h3 id="局限性" tabindex="-1">局限性 <a class="header-anchor" href="#局限性" aria-label="Permalink to &quot;局限性&quot;">​</a></h3><ul><li>EvoSkills 对比显示 Skill Creator 基线通过率仅 <strong>34.1%</strong>，人工引导式创建存在天花板</li><li>不支持从执行失败中自动发现新 Skill —— 作者必须先&quot;知道要创建什么 Skill&quot;</li><li>紧密绑定 Claude Code / Anthropic 生态</li></ul><hr><h2 id="成熟度评分" tabindex="-1">成熟度评分 <a class="header-anchor" href="#成熟度评分" aria-label="Permalink to &quot;成熟度评分&quot;">​</a></h2><table tabindex="0"><thead><tr><th>维度</th><th>评分</th><th>说明</th></tr></thead><tbody><tr><td>技术成熟度</td><td>0.75</td><td>官方工具，已在大量真实 Skill 中使用</td></tr><tr><td>创新性</td><td>0.45</td><td>Eval 闭环思路成熟，方法论本身渐进改进</td></tr><tr><td>落地程度</td><td>0.85</td><td>内置于官方课程与生态，广泛采用</td></tr><tr><td>生态活跃度</td><td>0.80</td><td>Anthropic 官方维护，Claude Code 社区贡献活跃</td></tr></tbody></table><p><strong>综合评分</strong>: <strong>0.71</strong></p><hr><h2 id="参考资料" tabindex="-1">参考资料 <a class="header-anchor" href="#参考资料" aria-label="Permalink to &quot;参考资料&quot;">​</a></h2><ul><li><a href="https://docs.claude.com/en/docs/agents-and-tools/agent-skills" target="_blank" rel="noreferrer">Anthropic Agent Skills 官方文档</a></li><li>对比基线：<a href="https://arxiv.org/abs/2604.01687" target="_blank" rel="noreferrer">EvoSkills 论文</a>（Skill Creator 34.1% vs EvoSkills 75%）</li></ul>',31)])])}const p=l(o,[["render",i]]);export{k as __pageData,p as default};
